import React from 'react';
import { View } from 'react-native';
import { fetch } from 'whatwg-fetch';

class NetworkingModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      apiResponse: null,
      localDeviceData: null,
    };
  }

  componentDidMount() {
    fetch('https://api.example.com')
      .then((response) => response.json())
      .then((data) => {
        this.setState({ apiResponse: data });
      })
      .catch((error) => console.error(error));
  }

  componentDidUpdate() {
    fetch('http://192.168.x.x')
      .then((response) => response.json())
      .then((data) => {
        this.setState({ localDeviceData: data });
      })
      .catch((error) => console.error(error));
  }

  render() {
    return (
      <View>
        {this.state.apiResponse && (
          <Text>{this.state.apiResponse}</Text>
        )}
        {this.state.localDeviceData && (
          <Text>{this.state.localDeviceData}</Text>
        )}
      </View>
    );
  }
}